use std::collections::BinaryHeap;

use rand::seq::SliceRandom;
use test::{Bencher, black_box};

#[bench]
fn bench_find_smallest_1000(b: &mut Bencher) {
    let mut rng = crate::bench_rng();
    let mut vec: Vec<u32> = (0..100_000).collect();
    vec.shuffle(&mut rng);

    b.iter(|| {
        let mut iter = vec.iter().copied();
        let mut heap: BinaryHeap<_> = iter.by_ref().take(1000).collect();

        for x in iter {
            let mut max = heap.peek_mut().unwrap();
            // This comparison should be true only 1% of the time.
            // Unnecessary `sift_down`s will degrade performance
            if x < *max {
                *max = x;
            }
        }

        heap
    })
}

#[bench]
fn bench_peek_mut_deref_mut(b: &mut Bencher) {
    let mut bheap = BinaryHeap::from(vec![42]);
    let vec: Vec<u32> = (0..1_000_000).collect();

    b.iter(|| {
        let vec = black_box(&vec);
        let mut peek_mut = bheap.peek_mut().unwrap();
        // The compiler shouldn't be able to optimize away the `sift_down`
        // assignment in `PeekMut`'s `DerefMut` implementation since
        // the loop might not run.
        for &i in vec.iter() {
            *peek_mut = i;
        }
        // Remove the already minimal overhead of the sift_down
        std::mem::forget(peek_mut);
    })
}

#[bench]
fn bench_from_vec(b: &mut Bencher) {
    let mut rng = crate::bench_rng();
    let mut vec: Vec<u32> = (0..100_000).collect();
    vec.shuffle(&mut rng);

    b.iter(|| BinaryHeap::from(vec.clone()))
}

#[bench]
fn bench_into_sorted_vec(b: &mut Bencher) {
    let bheap: BinaryHeap<i32> = (0..10_000).collect();

    b.iter(|| bheap.clone().into_sorted_vec())
}

#[bench]
fn bench_push(b: &mut Bencher) {
    let mut bheap = BinaryHeap::with_capacity(50_000);
    let mut rng = crate::bench_rng();
    let mut vec: Vec<u32> = (0..50_000).collect();
    vec.shuffle(&mut rng);

    b.iter(|| {
        for &i in vec.iter() {
            bheap.push(i);
        }
        black_box(&mut bheap);
        bheap.clear();
    })
}

#[bench]
fn bench_pop(b: &mut Bencher) {
    let mut bheap = BinaryHeap::with_capacity(10_000);

    b.iter(|| {
        bheap.extend((0..10_000).rev());
        black_box(&mut bheap);
        while let Some(elem) = bheap.pop() {
            black_box(elem);
        }
    })
}

use std::collections::HashMap;
use std::ffi::OsStr;
use std::path::Path;
use std::process::Command;

pub fn write_file(file_path: impl AsRef<Path>, content: &str) -> Result<(), String> {
    std::fs::write(&file_path, content).map_err(|error| {
        format!(
            "Failed to create empty `{}` file: {error:?}",
            file_path.as_ref().display(),
        )
    })
}

pub fn run_command_with_env<I, S>(
    bin: &str,
    args: I,
    current_dir: &str,
    env: &HashMap<&str, &str>,
) -> Result<(), String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    let exit_status = Command::new(bin)
        .args(args)
        .envs(env)
        .current_dir(current_dir)
        .spawn()
        .map_err(|error| format!("Failed to spawn command `{bin}`: {error:?}"))?
        .wait()
        .map_err(|error| format!("Failed to wait command `{bin}`: {error:?}"))?;
    if exit_status.success() {
        Ok(())
    } else {
        Err(format!("Command `{bin}` failed"))
    }
}

pub fn run_command<I, S>(bin: &str, args: I, current_dir: &str) -> Result<(), String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    run_command_with_env(bin, args, current_dir, &HashMap::new())
}

pub struct CommandOutput {
    pub output: String,
    pub exited_successfully: bool,
}

pub fn run_command_with_output_and_env<I, S>(
    bin: &str,
    args: I,
    current_dir: &str,
    env: &HashMap<&str, &str>,
) -> Result<CommandOutput, String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    let cmd_output = Command::new(bin)
        .args(args)
        .envs(env)
        .current_dir(current_dir)
        .output()
        .map_err(|error| format!("Failed to spawn command `{bin}`: {error:?}"))?;
    let mut output = String::from_utf8_lossy(&cmd_output.stdout).into_owned();
    output.push_str(&String::from_utf8_lossy(&cmd_output.stderr));
    Ok(CommandOutput {
        output,
        exited_successfully: cmd_output.status.success(),
    })
}

pub fn run_command_with_output<I, S>(
    bin: &str,
    args: I,
    current_dir: &str,
) -> Result<CommandOutput, String>
where
    I: IntoIterator<Item = S>,
    S: AsRef<OsStr>,
{
    run_command_with_output_and_env(bin, args, current_dir, &HashMap::new())
}

use super::ParallelIterator;
use super::plumbing::*;

use std::iter::{self, Product};
use std::marker::PhantomData;

pub(super) fn product<PI, P>(pi: PI) -> P
where
    PI: ParallelIterator,
    P: Send + Product<PI::Item> + Product,
{
    pi.drive_unindexed(ProductConsumer::new())
}

fn mul<T: Product>(left: T, right: T) -> T {
    [left, right].into_iter().product()
}

struct ProductConsumer<P: Send> {
    _marker: PhantomData<*const P>,
}

unsafe impl<P: Send> Send for ProductConsumer<P> {}

impl<P: Send> ProductConsumer<P> {
    fn new() -> ProductConsumer<P> {
        ProductConsumer {
            _marker: PhantomData,
        }
    }
}

impl<P, T> Consumer<T> for ProductConsumer<P>
where
    P: Send + Product<T> + Product,
{
    type Folder = ProductFolder<P>;
    type Reducer = Self;
    type Result = P;

    fn split_at(self, _index: usize) -> (Self, Self, Self) {
        (
            ProductConsumer::new(),
            ProductConsumer::new(),
            ProductConsumer::new(),
        )
    }

    fn into_folder(self) -> Self::Folder {
        ProductFolder {
            product: iter::empty::<T>().product(),
        }
    }

    fn full(&self) -> bool {
        false
    }
}

impl<P, T> UnindexedConsumer<T> for ProductConsumer<P>
where
    P: Send + Product<T> + Product,
{
    fn split_off_left(&self) -> Self {
        ProductConsumer::new()
    }

    fn to_reducer(&self) -> Self::Reducer {
        ProductConsumer::new()
    }
}

impl<P> Reducer<P> for ProductConsumer<P>
where
    P: Send + Product,
{
    fn reduce(self, left: P, right: P) -> P {
        mul(left, right)
    }
}

struct ProductFolder<P> {
    product: P,
}

impl<P, T> Folder<T> for ProductFolder<P>
where
    P: Product<T> + Product,
{
    type Result = P;

    fn consume(self, item: T) -> Self {
        ProductFolder {
            product: mul(self.product, iter::once(item).product()),
        }
    }

    fn consume_iter<I>(self, iter: I) -> Self
    where
        I: IntoIterator<Item = T>,
    {
        ProductFolder {
            product: mul(self.product, iter.into_iter().product()),
        }
    }

    fn complete(self) -> P {
        self.product
    }

    fn full(&self) -> bool {
        false
    }
}

use super::ParallelIterator;
use super::plumbing::*;

use std::iter::{self, Sum};
use std::marker::PhantomData;

pub(super) fn sum<PI, S>(pi: PI) -> S
where
    PI: ParallelIterator,
    S: Send + Sum<PI::Item> + Sum,
{
    pi.drive_unindexed(SumConsumer::new())
}

fn add<T: Sum>(left: T, right: T) -> T {
    [left, right].into_iter().sum()
}

struct SumConsumer<S: Send> {
    _marker: PhantomData<*const S>,
}

unsafe impl<S: Send> Send for SumConsumer<S> {}

impl<S: Send> SumConsumer<S> {
    fn new() -> SumConsumer<S> {
        SumConsumer {
            _marker: PhantomData,
        }
    }
}

impl<S, T> Consumer<T> for SumConsumer<S>
where
    S: Send + Sum<T> + Sum,
{
    type Folder = SumFolder<S>;
    type Reducer = Self;
    type Result = S;

    fn split_at(self, _index: usize) -> (Self, Self, Self) {
        (SumConsumer::new(), SumConsumer::new(), SumConsumer::new())
    }

    fn into_folder(self) -> Self::Folder {
        SumFolder {
            sum: iter::empty::<T>().sum(),
        }
    }

    fn full(&self) -> bool {
        false
    }
}

impl<S, T> UnindexedConsumer<T> for SumConsumer<S>
where
    S: Send + Sum<T> + Sum,
{
    fn split_off_left(&self) -> Self {
        SumConsumer::new()
    }

    fn to_reducer(&self) -> Self::Reducer {
        SumConsumer::new()
    }
}

impl<S> Reducer<S> for SumConsumer<S>
where
    S: Send + Sum,
{
    fn reduce(self, left: S, right: S) -> S {
        add(left, right)
    }
}

struct SumFolder<S> {
    sum: S,
}

impl<S, T> Folder<T> for SumFolder<S>
where
    S: Sum<T> + Sum,
{
    type Result = S;

    fn consume(self, item: T) -> Self {
        SumFolder {
            sum: add(self.sum, iter::once(item).sum()),
        }
    }

    fn consume_iter<I>(self, iter: I) -> Self
    where
        I: IntoIterator<Item = T>,
    {
        SumFolder {
            sum: add(self.sum, iter.into_iter().sum()),
        }
    }

    fn complete(self) -> S {
        self.sum
    }

    fn full(&self) -> bool {
        false
    }
}

use syntax::{AstNode, SyntaxKind, T, TextRange, ast};

use crate::{AssistContext, AssistId, Assists};

// Assist: remove_else_branches
//
// Removes the `else` keyword and else branches.
//
// ```
// fn main() {
//     if true {
//         let _ = 2;
//     } $0else {
//         unreachable!();
//     }
// }
// ```
// ->
// ```
// fn main() {
//     if true {
//         let _ = 2;
//     }
// }
// ```
// ---
// ```
// fn main() {
//     let _x = 2 $0else { unreachable!() };
// }
// ```
// ->
// ```
// fn main() {
//     let _x = 2;
// }
// ```
pub(crate) fn remove_else_branches(acc: &mut Assists, ctx: &AssistContext<'_, '_>) -> Option<()> {
    let else_token = ctx.find_token_syntax_at_offset(T![else])?;
    let else_branches = ctx
        .find_node_at_range::<ast::IfExpr>()
        .and_then(|if_expr| if_expr.else_branch()?.syntax().clone().into())
        .or_else(|| {
            ctx.find_node_at_range::<ast::LetStmt>()?
                .let_else()?
                .block_expr()?
                .syntax()
                .clone()
                .into()
        })?;

    let target = TextRange::cover(else_token.text_range(), else_branches.text_range());
    acc.add(
        AssistId::refactor("remove_else_branches"),
        "Remove `else` branches",
        target,
        |builder| {
            let editor = builder.make_editor(&else_token.parent().unwrap());
            match else_token.prev_token() {
                Some(it) if it.kind() == SyntaxKind::WHITESPACE => editor.delete(it),
                _ => (),
            }
            match else_token.next_token() {
                Some(it) if it.kind() == SyntaxKind::WHITESPACE => editor.delete(it),
                _ => (),
            }
            editor.delete(else_token);
            editor.delete(else_branches);
            builder.add_file_edits(ctx.vfs_file_id(), editor);
        },
    )
}

