#[cfg_attr(
    // Make sure that this is used on some platforms at least.
    not(any(target_os = "linux", target_os = "windows")),
    allow(dead_code)
)]
fn each_addr<A: crate::net::ToSocketAddrs, F, T>(addr: A, mut f: F) -> crate::io::Result<T>
where
    F: FnMut(&crate::net::SocketAddr) -> crate::io::Result<T>,
{
    use crate::io::Error;

    let mut last_err = None;
    for addr in addr.to_socket_addrs()? {
        match f(&addr) {
            Ok(l) => return Ok(l),
            Err(e) => last_err = Some(e),
        }
    }

    match last_err {
        Some(err) => Err(err),
        None => Err(Error::NO_ADDRESSES),
    }
}

// Default implementation, may be overridden by platform-specific implementations.
#[cfg(not(all(target_vendor = "fortanix", target_env = "sgx")))]
pub(crate) fn lookup_host_string(
    addr: &str,
) -> crate::io::Result<impl Iterator<Item = crate::net::SocketAddr>> {
    use crate::io;

    // Split the string by ':' and convert the second part to u16...
    let Some((host, port_str)) = addr.rsplit_once(':') else {
        return Err(io::const_error!(io::ErrorKind::InvalidInput, "invalid socket address"));
    };
    let Ok(port) = port_str.parse::<u16>() else {
        return Err(io::const_error!(io::ErrorKind::InvalidInput, "invalid port value"));
    };

    // ... and make the system look up the host.
    crate::sys::net::lookup_host(host, port)
}

use crate::num::NonZero;
use crate::thread::ThreadInit;
use crate::time::Duration;
use crate::{io, ptr};

pub type Tid = hermit_abi::Tid;

pub struct Thread {
    tid: Tid,
}

unsafe impl Send for Thread {}
unsafe impl Sync for Thread {}

pub const DEFAULT_MIN_STACK_SIZE: usize = 1 << 20;

impl Thread {
    pub unsafe fn new_with_coreid(
        stack: usize,
        init: Box<ThreadInit>,
        core_id: isize,
    ) -> io::Result<Thread> {
        let data = Box::into_raw(init);
        let tid = unsafe {
            hermit_abi::spawn2(
                thread_start,
                data.expose_provenance(),
                hermit_abi::Priority::into(hermit_abi::NORMAL_PRIO),
                stack,
                core_id,
            )
        };

        return if tid == 0 {
            // The thread failed to start and as a result data was not consumed. Therefore, it is
            // safe to reconstruct the box so that it gets deallocated.
            unsafe {
                drop(Box::from_raw(data));
            }
            Err(io::const_error!(io::ErrorKind::Uncategorized, "unable to create thread!"))
        } else {
            Ok(Thread { tid })
        };

        extern "C" fn thread_start(data: usize) {
            // SAFETY: we are simply recreating the box that was leaked earlier.
            let init =
                unsafe { Box::from_raw(ptr::with_exposed_provenance_mut::<ThreadInit>(data)) };
            let rust_start = init.init();
            rust_start();

            // Run all destructors.
            unsafe {
                crate::sys::thread_local::destructors::run();
            }
            crate::rt::thread_cleanup();
        }
    }

    pub unsafe fn new(stack: usize, init: Box<ThreadInit>) -> io::Result<Thread> {
        unsafe {
            Thread::new_with_coreid(stack, init, -1 /* = no specific core */)
        }
    }

    pub fn join(self) {
        unsafe {
            let _ = hermit_abi::join(self.tid);
        }
    }
}

pub fn available_parallelism() -> io::Result<NonZero<usize>> {
    unsafe { Ok(NonZero::new_unchecked(hermit_abi::available_parallelism())) }
}

#[inline]
pub fn sleep(dur: Duration) {
    let micros = dur.as_micros() + if dur.subsec_nanos() % 1_000 > 0 { 1 } else { 0 };
    let micros = u64::try_from(micros).unwrap_or(u64::MAX);

    unsafe {
        hermit_abi::usleep(micros);
    }
}

#[inline]
pub fn yield_now() {
    unsafe {
        hermit_abi::yield_now();
    }
}

#[macro_export]
macro_rules! format_list_container {
    ($e:expr, $start:tt, $end:tt) => {{
        use std::fmt::Write;
        let mut out = String::new();
        out.push($start);
        let mut iter = $e.into_iter();
        let mut next = iter.next();

        loop {
            if let Some(val) = next {
                write!(out, "{val}").unwrap();
            };
            next = iter.next();
            if next.is_some() {
                out.push_str(", ")
            } else {
                break;
            }
        }
        out.push($end);
        out
    }};
}

#[macro_export]
macro_rules! format_list {
    ($e:expr) => {{
        use polars_utils::format_list_container;
        format_list_container!($e, '[', ']')
    }};
}

#[macro_export]
macro_rules! format_tuple {
    ($e:expr) => {{
        use polars_utils::format_list_container;
        format_list_container!($e, '(', ')')
    }};
}

#[macro_export]
macro_rules! format_list_container_truncated {
    ($e:expr, $start:tt, $end:tt, $max:expr, $quote:expr) => {{
        use std::fmt::Write;
        let mut out = String::new();
        out.push($start);
        let mut iter = $e.into_iter();
        let mut next = iter.next();

        let mut count = 0;
        loop {
            if $max == count {
                write!(out, "...").unwrap();
                break;
            }
            count += 1;

            if let Some(val) = next {
                write!(out, "{}{}{}", $quote, val, $quote).unwrap();
            };
            next = iter.next();
            if next.is_some() {
                out.push_str(", ")
            } else {
                break;
            }
        }
        out.push($end);
        out
    }};
}

#[macro_export]
macro_rules! format_list_truncated {
    ($e:expr, $max:expr) => {{
        use polars_utils::format_list_container_truncated;
        format_list_container_truncated!($e, '[', ']', $max, "")
    }};
    ($e:expr, $max:expr, $quote:expr) => {{
        use polars_utils::format_list_container_truncated;
        format_list_container_truncated!($e, '[', ']', $max, $quote)
    }};
}

